var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"하, 할 수 있다. 더듬지 않는다.","JPN":"ちゃ、ちゃんとできる。どもったりしない。","ENG":"I-I can do this. I won't stutter.","TWN":"這、這次一定能做到，不會再結巴了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"하나......둘......셋......","JPN":"いち……にぃ……さん……","ENG":"One, two, three...","TWN":"一……二……三……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"후우......","JPN":"ふぅ……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#83dcb7>MIYA님이 스트리밍을 시작했습니다.</color>   ","JPN":"<color=#83dcb7>MIYAさんがライブ配信を開始しました。</color>   ","ENG":"<color=#83dcb7>MIYA began her livestream.</color>   ","TWN":"<color=#83dcb7>MIYA大人開始直播了。</color>","THA":"<color=#83dcb7>มียาเริ่มถ่ายทอดสด</color>   ","VTN":"<color=#83dcb7>MIYA đã bắt đầu buổi phát trực tiếp của cô ấy.</color>   ","SCN":"<color=#83dcb7>米娅大人开始直播了。</color>","DEU":"<color=#83dcb7>MIYA hat den Livestream gestartet.</color>   ","FRA":"<color=#83dcb7>MIYA a commencé son stream.</color>   "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"모두 안녕하세요! 미하!","JPN":"みんな、こんにちは！　ミハー！","ENG":"Hi everyone! It's me, Miya!","TWN":"大家好！米哈！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"오늘은 미야 채널 1주년 라이브를 축하하는 시간을 갖겠습니다~","JPN":"今日は、ミヤチャンネルの開設1周年を祝う配信にしたいと思います～。","ENG":"Today, we'll celebrate the 1-year anniversary of livestreaming on the Miya channel.","TWN":"今天是慶祝米婭頻道直播一周年的特別節目～"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"헤헤...... 오늘도...... 제 방송에 와주셔서 다들 고마워요.","JPN":"えへへ……今日も……ミヤチャンネルに来てくれた皆さん、ありがとうございます。","ENG":"Heh heh... Thank you all... for watching my show again today.","TWN":"嘿嘿……今天也……謝謝大家來看我的直播。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#83dcb7>근데 미야는 야외방송 같은 거 안 해?</color>","JPN":"<color=#83dcb7>ところで、ミヤは野外配信とかはしないの？</color>","ENG":"<color=#83dcb7>Don't you ever shoot outdoor episodes, Miya?</color>","TWN":"<color=#83dcb7>話說。米婭妳不嘗試一下在室外直播嗎？</color>"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Sorry?","TWN":"什麼……？"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"바깥에 나가는 건 좀...... 사람이 많으면 무섭기도 하고......","JPN":"お外に出るのはちょっと……人混みは怖いですし……","ENG":"Well, going outside is a bit scary, when there's lots of people...","TWN":"去外面有點……人很多也很可怕……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"저...... 그러니까 전......","JPN":"えっと……ですから、ミヤは……","ENG":"Erm, so I...","TWN":"我……所以我……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"여러분이랑 얘기 나누고 그러는 게 좋고...... 지금은 그거에 만족하고 있고......","JPN":"皆さんとお話したりするのが楽しくて……今は、それで満足してまして……","ENG":"I enjoy speaking with you... and I'm satisfied with that...","TWN":"更喜歡在這裡跟大家一起聊天……現在這樣就很滿足了……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#83dcb7>요즘 같은 세상엔 이불 밖이 위험하긴 하지.</color>","JPN":"<color=#83dcb7>このご時世、お布団の外は危ないっていうしな。</color>","ENG":"<color=#83dcb7>Well, I guess it's dangerous beyond the blankets these days.</color>","TWN":"<color=#83dcb7>現在這種世道，出了被窩就會遇到危險了呢。</color>"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#83dcb7>카운터도 겁이 많구나, 의외네.</color>","JPN":"<color=#83dcb7>怖がりなカウンターもいるんだね。意外～。</color>","ENG":"<color=#83dcb7>Wow, I didn't know Counters get so scared too.</color>","TWN":"<color=#83dcb7>想不到制裁者都也會害怕啊，真是意外。</color>"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아뇨! 그건 제가 좀 유별난 것뿐이에요!","JPN":"いいえ！　ミヤがちょっと変わってるだけなんです！","ENG":"No! I'm just an oddball!","TWN":"不是的！只是我比較怪而已！"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"다른 카운터들은......","JPN":"他のカウンターの方々は……","ENG":"The other Counters...","TWN":"其他的制裁者……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아니, 대부분의 사람들은...... 저보다 나을 거에요.","JPN":"いえ、世の中のほとんどの人は……ミヤよりマシなはずです。","ENG":"Actually, most other people... are probably better than me.","TWN":"不，大部分的人……都比我優秀。"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"학교에서도 친구들이랑 어울려본 적 없고...... 그러다 보니 말수도 계속 줄어들고......","JPN":"ミヤは学校で友達と遊んだりしてなくて……それで、口数もどんどん減っていって……","ENG":"I never hung out with the other kids in school, and that made me talk even less each day...","TWN":"在學校我也從交不到朋友……所以話就越來越少……"},"stage":{"bg":"DORMITORY_1","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};